32	inline constexpr NGP_HOST_DEVICE float SQRT3() { return 1.73205080757f; }
33	inline constexpr NGP_HOST_DEVICE float STEPSIZE() { return (SQRT3() / NERF_STEPS()); } // for nerf raymarch
34	inline constexpr NGP_HOST_DEVICE float MIN_CONE_STEPSIZE() { return STEPSIZE(); }
35	// Maximum step size is the width of the coarsest gridsize cell.
36	inline constexpr NGP_HOST_DEVICE float MAX_CONE_STEPSIZE() { return STEPSIZE() * (1<<(NERF_CASCADES()-1)) * NERF_STEPS() / NERF_GRIDSIZE(); }
