61	
62	struct LossAndGradient {
63		vec3 loss;
64		vec3 gradient;
65	
66		NGP_HOST_DEVICE LossAndGradient operator*(float scalar) {
67			return {loss * scalar, gradient * scalar};
68		}
69	
70		NGP_HOST_DEVICE LossAndGradient operator/(float scalar) {
71			return {loss / scalar, gradient / scalar};
72		}
73	};
74	
75	inline NGP_HOST_DEVICE LossAndGradient l2_loss(const vec3& target, const vec3& prediction) {
76		vec3 difference = prediction - target;
77		return {
78			difference * difference,
79			2.0f * difference
80		};
81	}
82	
83	inline NGP_HOST_DEVICE LossAndGradient relative_l2_loss(const vec3& target, const vec3& prediction) {
84		vec3 difference = prediction - target;
85		vec3 denom = prediction * prediction + 1e-2f;
86		return {
87			difference * difference / denom,
88			2.0f * difference / denom
89		};
90	}
91	
92	inline NGP_HOST_DEVICE LossAndGradient l1_loss(const vec3& target, const vec3& prediction) {
93		vec3 difference = prediction - target;
94		return {
95			abs(difference),
96			copysign(vec3(1.0f), difference),
97		};
98	}
99	
100	inline NGP_HOST_DEVICE LossAndGradient huber_loss(const vec3& target, const vec3& prediction, float alpha = 1) {
101		vec3 difference = prediction - target;
102		vec3 abs_diff = abs(difference);
103		vec3 square = 0.5f/alpha * difference * difference;
104		return {
105			{
106				abs_diff.x > alpha ? (abs_diff.x - 0.5f * alpha) : square.x,
107				abs_diff.y > alpha ? (abs_diff.y - 0.5f * alpha) : square.y,
108				abs_diff.z > alpha ? (abs_diff.z - 0.5f * alpha) : square.z,
109			},
110			{
111				abs_diff.x > alpha ? (difference.x > 0 ? 1.0f : -1.0f) : (difference.x / alpha),
112				abs_diff.y > alpha ? (difference.y > 0 ? 1.0f : -1.0f) : (difference.y / alpha),
113				abs_diff.z > alpha ? (difference.z > 0 ? 1.0f : -1.0f) : (difference.z / alpha),
114			},
115		};
116	}
117	
118	inline NGP_HOST_DEVICE LossAndGradient log_l1_loss(const vec3& target, const vec3& prediction) {
119		vec3 difference = prediction - target;
120		vec3 divisor = abs(difference) + 1.0f;
121		return {
122			log(divisor),
123			copysign(vec3(1.0f) / divisor, difference),
124		};
125	}
126	
127	inline NGP_HOST_DEVICE LossAndGradient smape_loss(const vec3& target, const vec3& prediction) {
128		vec3 difference = prediction - target;
129		vec3 denom = 0.5f * (abs(prediction) + abs(target)) + 1e-2f;
130		return {
131			abs(difference) / denom,
132			copysign(vec3(1.0f) / denom, difference),
133		};
134	}
135	
136	inline NGP_HOST_DEVICE LossAndGradient mape_loss(const vec3& target, const vec3& prediction) {
137		vec3 difference = prediction - target;
138		vec3 denom = abs(prediction) + 1e-2f;
139		return {
140			abs(difference) / denom,
141			copysign(vec3(1.0f) / denom, difference),
142		};
143	}
