176	struct NerfCoordinate {
177		NGP_HOST_DEVICE NerfCoordinate(const vec3& pos, const vec3& dir, float dt) : pos{pos, dt}, dt{dt}, dir{dir, dt} {}
178		NGP_HOST_DEVICE void set_with_optional_extra_dims(const vec3& pos, const vec3& dir, float dt, const float* extra_dims, uint32_t stride_in_bytes) {
179			this->dt = dt;
180			this->pos = NerfPosition(pos, dt);
181			this->dir = NerfDirection(dir, dt);
182			copy_extra_dims(extra_dims, stride_in_bytes);
183		}
184		inline NGP_HOST_DEVICE const float* get_extra_dims() const { return (const float*)(this + 1); }
185		inline NGP_HOST_DEVICE float* get_extra_dims() { return (float*)(this + 1); }
186	
187		NGP_HOST_DEVICE void copy(const NerfCoordinate& inp, uint32_t stride_in_bytes) {
188			*this = inp;
189			copy_extra_dims(inp.get_extra_dims(), stride_in_bytes);
190		}
191		NGP_HOST_DEVICE inline void copy_extra_dims(const float *extra_dims, uint32_t stride_in_bytes) {
192			if (stride_in_bytes >= sizeof(NerfCoordinate)) {
193				float* dst = get_extra_dims();
194				const uint32_t n_extra = (stride_in_bytes - sizeof(NerfCoordinate)) / sizeof(float);
195				for (uint32_t i = 0; i < n_extra; ++i) dst[i] = extra_dims[i];
196			}
197		}
