204	inline NGP_HOST_DEVICE float network_to_rgb(float val, ENerfActivation activation) {
205		switch (activation) {
206			case ENerfActivation::None: return val;
207			case ENerfActivation::ReLU: return val > 0.0f ? val : 0.0f;
208			case ENerfActivation::Logistic: return logistic(val);
209			case ENerfActivation::Exponential: return expf(clamp(val, -10.0f, 10.0f));
210			default: assert(false);
211		}
212		return 0.0f;
213	}
214	
215	inline NGP_HOST_DEVICE float network_to_rgb_derivative(float val, ENerfActivation activation) {
216		switch (activation) {
217			case ENerfActivation::None: return 1.0f;
218			case ENerfActivation::ReLU: return val > 0.0f ? 1.0f : 0.0f;
219			case ENerfActivation::Logistic: { float density = logistic(val); return density * (1 - density); };
220			case ENerfActivation::Exponential: return expf(clamp(val, -10.0f, 10.0f));
221			default: assert(false);
222		}
223		return 0.0f;
224	}
225	
226	template <typename T>
227	NGP_HOST_DEVICE vec3 network_to_rgb_derivative_vec(const T& val, ENerfActivation activation) {
228		return {
229			network_to_rgb_derivative(float(val[0]), activation),
230			network_to_rgb_derivative(float(val[1]), activation),
231			network_to_rgb_derivative(float(val[2]), activation),
232		};
233	}
234	
235	inline NGP_HOST_DEVICE float network_to_density(float val, ENerfActivation activation) {
236		switch (activation) {
237			case ENerfActivation::None: return val;
238			case ENerfActivation::ReLU: return val > 0.0f ? val : 0.0f;
239			case ENerfActivation::Logistic: return logistic(val);
240			case ENerfActivation::Exponential: return expf(val);
241			default: assert(false);
242		}
243		return 0.0f;
244	}
245	
246	inline NGP_HOST_DEVICE float network_to_density_derivative(float val, ENerfActivation activation) {
247		switch (activation) {
248			case ENerfActivation::None: return 1.0f;
249			case ENerfActivation::ReLU: return val > 0.0f ? 1.0f : 0.0f;
250			case ENerfActivation::Logistic: { float density = logistic(val); return density * (1 - density); };
251			case ENerfActivation::Exponential: return expf(clamp(val, -15.0f, 15.0f));
252			default: assert(false);
253		}
254		return 0.0f;
255	}
256	
257	template <typename T>
258	NGP_HOST_DEVICE vec3 network_to_rgb_vec(const T& val, ENerfActivation activation) {
259		return {
260			network_to_rgb(float(val[0]), activation),
261			network_to_rgb(float(val[1]), activation),
262			network_to_rgb(float(val[2]), activation),
263		};
264	}
265	
266	inline NGP_HOST_DEVICE vec3 warp_position(const vec3& pos, const BoundingBox& aabb) {
267		// return {logistic(pos.x - 0.5f), logistic(pos.y - 0.5f), logistic(pos.z - 0.5f)};
268		// return pos;
269	
270		return aabb.relative_pos(pos);
271	}
272	
273	inline NGP_HOST_DEVICE vec3 unwarp_position(const vec3& pos, const BoundingBox& aabb) {
274		// return {logit(pos.x) + 0.5f, logit(pos.y) + 0.5f, logit(pos.z) + 0.5f};
275		// return pos;
276	
277		return aabb.min + pos * aabb.diag();
278	}
279	
280	inline NGP_HOST_DEVICE vec3 unwarp_position_derivative(const vec3& pos, const BoundingBox& aabb) {
281		// return {logit(pos.x) + 0.5f, logit(pos.y) + 0.5f, logit(pos.z) + 0.5f};
282		// return pos;
283	
284		return aabb.diag();
285	}
286	
287	inline NGP_HOST_DEVICE vec3 warp_position_derivative(const vec3& pos, const BoundingBox& aabb) {
288		return vec3(1.0f) / unwarp_position_derivative(pos, aabb);
289	}
290	
291	inline NGP_HOST_DEVICE vec3 warp_direction(const vec3& dir) {
292		return (dir + 1.0f) * 0.5f;
293	}
294	
295	inline NGP_HOST_DEVICE vec3 unwarp_direction(const vec3& dir) {
296		return dir * 2.0f - 1.0f;
297	}
298	
299	inline NGP_HOST_DEVICE vec3 warp_direction_derivative(const vec3& dir) {
300		return vec3(0.5f);
301	}
302	
303	inline NGP_HOST_DEVICE vec3 unwarp_direction_derivative(const vec3& dir) {
304		return vec3(2.0f);
305	}
306	
307	inline NGP_HOST_DEVICE float warp_dt(float dt) {
308		float max_stepsize = MIN_CONE_STEPSIZE() * (1<<(NERF_CASCADES()-1));
309		return (dt - MIN_CONE_STEPSIZE()) / (max_stepsize - MIN_CONE_STEPSIZE());
310	}
311	
312	inline NGP_HOST_DEVICE float unwarp_dt(float dt) {
313		float max_stepsize = MIN_CONE_STEPSIZE() * (1<<(NERF_CASCADES()-1));
314		return dt * (max_stepsize - MIN_CONE_STEPSIZE()) + MIN_CONE_STEPSIZE();
315	}
316	
317	inline NGP_HOST_DEVICE uint32_t cascaded_grid_idx_at(vec3 pos, uint32_t mip) {
318		float mip_scale = scalbnf(1.0f, -mip);
319		pos -= vec3(0.5f);
320		pos *= mip_scale;
321		pos += vec3(0.5f);
322	
323		ivec3 i = pos * (float)NERF_GRIDSIZE();
324		if (i.x < 0 || i.x >= NERF_GRIDSIZE() || i.y < 0 || i.y >= NERF_GRIDSIZE() || i.z < 0 || i.z >= NERF_GRIDSIZE()) {
325			return 0xFFFFFFFF;
326		}
327	
328		return morton3D(i.x, i.y, i.z);
329	}
330	
331	inline NGP_HOST_DEVICE uint32_t grid_mip_offset(uint32_t mip) {
332		return NERF_GRID_N_CELLS() * mip;
333	}
334	
335	inline NGP_HOST_DEVICE bool density_grid_occupied_at(const vec3& pos, const uint8_t* density_grid_bitfield, uint32_t mip) {
336		uint32_t idx = cascaded_grid_idx_at(pos, mip);
337		if (idx == 0xFFFFFFFF) {
338			return false;
339		}
340		return density_grid_bitfield[idx/8+grid_mip_offset(mip)/8] & (1<<(idx%8));
341	}
342	
343	inline NGP_HOST_DEVICE float cascaded_grid_at(vec3 pos, const float* cascaded_grid, uint32_t mip) {
344		uint32_t idx = cascaded_grid_idx_at(pos, mip);
345		if (idx == 0xFFFFFFFF) {
346			return 0.0f;
347		}
348		return cascaded_grid[idx+grid_mip_offset(mip)];
349	}
350	
351	inline NGP_HOST_DEVICE float& cascaded_grid_at(vec3 pos, float* cascaded_grid, uint32_t mip) {
352		uint32_t idx = cascaded_grid_idx_at(pos, mip);
353		if (idx == 0xFFFFFFFF) {
354			idx = 0;
355			printf("WARNING: invalid cascaded grid access.");
356		}
357		return cascaded_grid[idx+grid_mip_offset(mip)];
358	}
359	
360	inline NGP_HOST_DEVICE float distance_to_next_voxel(const vec3& pos, const vec3& dir, const vec3& idir, float res) { // dda like step
361		vec3 p = res * (pos - 0.5f);
362		float tx = (floorf(p.x + 0.5f + 0.5f * sign(dir.x)) - p.x) * idir.x;
363		float ty = (floorf(p.y + 0.5f + 0.5f * sign(dir.y)) - p.y) * idir.y;
364		float tz = (floorf(p.z + 0.5f + 0.5f * sign(dir.z)) - p.z) * idir.z;
365		float t = min(min(tx, ty), tz);
366	
367		return fmaxf(t / res, 0.0f);
368	}
369	
370	inline NGP_HOST_DEVICE float calc_cone_angle(float cosine, const vec2& focal_length, float cone_angle_constant) {
371		// Pixel size. Doesn't always yield a good performance vs. quality
372		// trade off. Especially if training pixels have a much different
373		// size than rendering pixels.
374		// return cosine*cosine / focal_length.mean();
375	
376		return cone_angle_constant;
377	}
378	
379	inline NGP_HOST_DEVICE float to_stepping_space(float t, float cone_angle) {
380		if (cone_angle <= 1e-5f) {
381			return t / MIN_CONE_STEPSIZE();
382		}
383	
384		float log1p_c = logf(1.0f + cone_angle);
385	
386		float a = (logf(MIN_CONE_STEPSIZE()) - logf(log1p_c)) / log1p_c;
387		float b = (logf(MAX_CONE_STEPSIZE()) - logf(log1p_c)) / log1p_c;
388	
389		float at = expf(a * log1p_c);
390		float bt = expf(b * log1p_c);
391	
392		if (t <= at) {
393			return (t - at) / MIN_CONE_STEPSIZE() + a;
394		} else if (t <= bt) {
395			return logf(t) / log1p_c;
396		} else {
397			return (t - bt) / MAX_CONE_STEPSIZE() + b;
398		}
399	}
400	
401	inline NGP_HOST_DEVICE float from_stepping_space(float n, float cone_angle) {
402		if (cone_angle <= 1e-5f) {
403			return n * MIN_CONE_STEPSIZE();
404		}
405	
406		float log1p_c = logf(1.0f + cone_angle);
407	
408		float a = (logf(MIN_CONE_STEPSIZE()) - logf(log1p_c)) / log1p_c;
409		float b = (logf(MAX_CONE_STEPSIZE()) - logf(log1p_c)) / log1p_c;
410	
411		float at = expf(a * log1p_c);
412		float bt = expf(b * log1p_c);
413	
414		if (n <= a) {
415			return (n - a) * MIN_CONE_STEPSIZE() + at;
416		} else if (n <= b) {
417			return expf(n * log1p_c);
418		} else {
419			return (n - b) * MAX_CONE_STEPSIZE() + bt;
420		}
421	}
422	
423	inline NGP_HOST_DEVICE float advance_n_steps(float t, float cone_angle, float n) {
424		return from_stepping_space(to_stepping_space(t, cone_angle) + n, cone_angle);
425	}
426	
427	inline NGP_HOST_DEVICE float calc_dt(float t, float cone_angle) {
428		return advance_n_steps(t, cone_angle, 1.0f) - t;
429	}
430	
431	inline NGP_HOST_DEVICE float advance_to_next_voxel(float t, float cone_angle, const vec3& pos, const vec3& dir, const vec3& idir, uint32_t mip) {
432		float res = scalbnf(NERF_GRIDSIZE(), -(int)mip);
433	
434		float t_target = t + distance_to_next_voxel(pos, dir, idir, res);
435	
436		// Analytic stepping in multiples of 1 in the "log-space" of our exponential stepping routine
437		t = to_stepping_space(t, cone_angle);
438		t_target = to_stepping_space(t_target, cone_angle);
439	
440		return from_stepping_space(t + ceilf(fmaxf(t_target - t, 0.5f)), cone_angle);
441	}
442	
443	inline NGP_HOST_DEVICE uint32_t mip_from_pos(const vec3& pos, uint32_t max_cascade = NERF_CASCADES()-1) {
444		int exponent;
445		float maxval = max(abs(pos - 0.5f));
446		frexpf(maxval, &exponent);
447		return (uint32_t)clamp(exponent+1, 0, (int)max_cascade);
448	}
449	
450	inline NGP_HOST_DEVICE uint32_t mip_from_dt(float dt, const vec3& pos, uint32_t max_cascade = NERF_CASCADES()-1) {
451		uint32_t mip = mip_from_pos(pos, max_cascade);
452		dt *= 2 * NERF_GRIDSIZE();
453		if (dt < 1.0f) {
454			return mip;
455		}
456	
457		int exponent;
458		frexpf(dt, &exponent);
459		return (uint32_t)clamp((int)mip, exponent, (int)max_cascade);
460	}
461	
462	template <bool MIP_FROM_DT=false>
463	NGP_HOST_DEVICE float if_unoccupied_advance_to_next_occupied_voxel(
464		float t,
465		float cone_angle,
466		const Ray& ray,
467		const vec3& idir,
468		const uint8_t* __restrict__ density_grid,
469		uint32_t min_mip,
470		uint32_t max_mip,
471		BoundingBox aabb,
472		mat3 aabb_to_local = mat3::identity()
473	) {
474		while (true) {
475			vec3 pos = ray(t);
476			if (t >= MAX_DEPTH() || !aabb.contains(aabb_to_local * pos)) {
477				return MAX_DEPTH();
478			}
479	
480			uint32_t mip = clamp(MIP_FROM_DT ? mip_from_dt(calc_dt(t, cone_angle), pos) : mip_from_pos(pos), min_mip, max_mip);
481	
482			if (!density_grid || density_grid_occupied_at(pos, density_grid, mip)) {
483				return t;
484			}
485	
486			// Find largest empty voxel surrounding us, such that we can advance as far as possible in the next step.
487			// Other places that do voxel stepping don't need this, because they don't rely on thread coherence as
488			// much as this one here.
489			while (mip < max_mip && !density_grid_occupied_at(pos, density_grid, mip+1)) {
490				++mip;
491			}
492	
493			t = advance_to_next_voxel(t, cone_angle, pos, ray.d, idir, mip);
494		}
495	}
496	
497	static constexpr float UNIFORM_SAMPLING_FRACTION = 0.5f;
498	
499	inline NGP_HOST_DEVICE vec2 sample_cdf_2d(vec2 sample, uint32_t img, const ivec2& res, const float* __restrict__ cdf_x_cond_y, const float* __restrict__ cdf_y, float* __restrict__ pdf) {
500		if (sample.x < UNIFORM_SAMPLING_FRACTION) {
501			sample.x /= UNIFORM_SAMPLING_FRACTION;
502			return sample;
503		}
504	
505		sample.x = (sample.x - UNIFORM_SAMPLING_FRACTION) / (1.0f - UNIFORM_SAMPLING_FRACTION);
506	
507		cdf_y += img * res.y;
508	
509		// First select row according to cdf_y
510		uint32_t y = binary_search(sample.y, cdf_y, res.y);
511		float prev = y > 0 ? cdf_y[y-1] : 0.0f;
512		float pmf_y = cdf_y[y] - prev;
513		sample.y = (sample.y - prev) / pmf_y;
514	
515		cdf_x_cond_y += img * res.y * res.x + y * res.x;
516	
517		// Then, select col according to x
518		uint32_t x = binary_search(sample.x, cdf_x_cond_y, res.x);
519		prev = x > 0 ? cdf_x_cond_y[x-1] : 0.0f;
520		float pmf_x = cdf_x_cond_y[x] - prev;
521		sample.x = (sample.x - prev) / pmf_x;
522	
523		if (pdf) {
524			*pdf = pmf_x * pmf_y * product(res);
525		}
526	
527		return {((float)x + sample.x) / (float)res.x, ((float)y + sample.y) / (float)res.y};
528	}
529	
530	inline NGP_HOST_DEVICE float pdf_2d(vec2 sample, uint32_t img, const ivec2& res, const float* __restrict__ cdf_x_cond_y, const float* __restrict__ cdf_y) {
531		ivec2 p = clamp(ivec2(sample * vec2(res)), 0, res - 1);
532	
533		cdf_y += img * res.y;
534		cdf_x_cond_y += img * res.y * res.x + p.y * res.x;
535	
536		float pmf_y = cdf_y[p.y];
537		if (p.y > 0) {
538			pmf_y -= cdf_y[p.y-1];
539		}
540	
541		float pmf_x = cdf_x_cond_y[p.x];
542		if (p.x > 0) {
543			pmf_x -= cdf_x_cond_y[p.x-1];
544		}
545	
546		// Probability mass of picking the pixel
547		float pmf = pmf_x * pmf_y;
548	
549		// To convert to probability density, divide by area of pixel
550		return UNIFORM_SAMPLING_FRACTION + pmf * product(res) * (1.0f - UNIFORM_SAMPLING_FRACTION);
551	}
552	
553	inline __device__ vec2 nerf_random_image_pos_training(default_rng_t& rng, const ivec2& resolution, bool snap_to_pixel_centers, const float* __restrict__ cdf_x_cond_y, const float* __restrict__ cdf_y, const ivec2& cdf_res, uint32_t img, float* __restrict__ pdf = nullptr) {
554		vec2 uv = random_val_2d(rng);
555	
556		if (cdf_x_cond_y) {
557			uv = sample_cdf_2d(uv, img, cdf_res, cdf_x_cond_y, cdf_y, pdf);
558		} else {
559			// // Warp-coherent tile
560			// uv.x = __shfl_sync(0xFFFFFFFF, uv.x, 0);
561			// uv.y = __shfl_sync(0xFFFFFFFF, uv.y, 0);
562	
563			// const ivec2 TILE_SIZE = {8, 4};
564			// uv = (uv * vec2(resolution - TILE_SIZE) + vec2(tcnn::lane_id() % TILE_SIZE.x, tcnn::lane_id() / threadIdx.x)) / vec2(resolution);
565	
566			if (pdf) {
567				*pdf = 1.0f;
568			}
569		}
570	
571		if (snap_to_pixel_centers) {
572			uv = (vec2(clamp(ivec2(uv * vec2(resolution)), 0, resolution - 1)) + 0.5f) / vec2(resolution);
573		}
574	
575		return uv;
576	}
577	
578	inline NGP_HOST_DEVICE uint32_t image_idx(uint32_t base_idx, uint32_t n_rays, uint32_t n_rays_total, uint32_t n_training_images, const float* __restrict__ cdf = nullptr, float* __restrict__ pdf = nullptr) {
579		if (cdf) {
580			float sample = ld_random_val(base_idx/* + n_rays_total*/, 0xdeadbeef);
581			// float sample = random_val(base_idx/* + n_rays_total*/);
582			uint32_t img = binary_search(sample, cdf, n_training_images);
583	
584			if (pdf) {
585				float prev = img > 0 ? cdf[img-1] : 0.0f;
586				*pdf = (cdf[img] - prev) * n_training_images;
587			}
588	
589			return img;
590		}
591	
592		// return ((base_idx/* + n_rays_total*/) * 56924617 + 96925573) % n_training_images;
593	
594		// Neighboring threads in the warp process the same image. Increases locality.
595		if (pdf) {
596			*pdf = 1.0f;
597		}
598		return (((base_idx/* + n_rays_total*/) * n_training_images) / n_rays) % n_training_images;
599	}
600	
601	inline NGP_HOST_DEVICE LossAndGradient loss_and_gradient(const vec3& target, const vec3& prediction, ELossType loss_type) {
602		switch (loss_type) {
603			case ELossType::RelativeL2:  return relative_l2_loss(target, prediction); break;
604			case ELossType::L1:          return l1_loss(target, prediction); break;
605			case ELossType::Mape:        return mape_loss(target, prediction); break;
606			case ELossType::Smape:       return smape_loss(target, prediction); break;
607			// Note: we divide the huber loss by a factor of 5 such that its L2 region near zero
608			// matches with the L2 loss and error numbers become more comparable. This allows reading
609			// off dB numbers of ~converged models and treating them as approximate PSNR to compare
610			// with other NeRF methods. Self-normalizing optimizers such as Adam are agnostic to such
611			// constant factors; optimization is therefore unaffected.
612			case ELossType::Huber:       return huber_loss(target, prediction, 0.1f) / 5.0f; break;
613			case ELossType::LogL1:       return log_l1_loss(target, prediction); break;
614			default: case ELossType::L2: return l2_loss(target, prediction); break;
615		}
616	}
617	
618	}
