866		EColorSpace color_space,
867		bool train_with_random_bg_color,
868		bool train_in_linear_colors,
869		const uint32_t n_training_images,
870		const TrainingImageMetadata* __restrict__ metadata,
871		const network_precision_t* network_output,
872		uint32_t* __restrict__ numsteps_counter,
873		const uint32_t* __restrict__ ray_indices_in,
874		const Ray* __restrict__ rays_in_unnormalized,
875		uint32_t* __restrict__ numsteps_in,
876		PitchedPtr<const NerfCoordinate> coords_in,
877		PitchedPtr<NerfCoordinate> coords_out,
878		network_precision_t* dloss_doutput,
879		ELossType loss_type,
880		ELossType depth_loss_type,
881		float* __restrict__ loss_output,
882		bool max_level_rand_training,
883		float* __restrict__ max_level_compacted_ptr,
884		ENerfActivation rgb_activation,
885		ENerfActivation density_activation,
886		bool snap_to_pixel_centers,
887		float* __restrict__ error_map,
888		const float* __restrict__ cdf_x_cond_y,
889		const float* __restrict__ cdf_y,
890		const float* __restrict__ cdf_img,
891		const ivec2 error_map_res,
892		const ivec2 error_map_cdf_res,
893		const float* __restrict__ sharpness_data,
894		ivec2 sharpness_resolution,
895		float* __restrict__ sharpness_grid,
896		float* __restrict__ density_grid,
897		const float* __restrict__ mean_density_ptr,
898		uint32_t max_mip,
899		const vec3* __restrict__ exposure,
900		vec3* __restrict__ exposure_gradient,
901		float depth_supervision_lambda,
902		float near_distance
903	) {
904		const uint32_t i = threadIdx.x + blockIdx.x * blockDim.x;
905		if (i >= *rays_counter) {
906			return;
907		}
908	
909		// grab the number of samples for this ray, and the first sample
910		uint32_t numsteps = numsteps_in[i * 2 + 0];
911		uint32_t base = numsteps_in[i * 2 + 1];
912	
913		coords_in += base;
914		network_output += base * padded_output_width;
915	
916		float T = 1.f;
917	
918		float EPSILON = 1e-4f;
919	
920		vec3 rgb_ray = vec3(0.0f);
921		vec3 hitpoint = vec3(0.0f);
922	
923		float depth_ray = 0.f;
924		uint32_t compacted_numsteps = 0;
925		vec3 ray_o = rays_in_unnormalized[i].o;
926		for (; compacted_numsteps < numsteps; ++compacted_numsteps) {
927			if (T < EPSILON) {
928				break;
929			}
930	
931			const tvec<network_precision_t, 4> local_network_output = *(tvec<network_precision_t, 4>*)network_output;
932			const vec3 rgb = network_to_rgb_vec(local_network_output, rgb_activation);
933			const vec3 pos = unwarp_position(coords_in.ptr->pos.p, aabb);
934			const float dt = unwarp_dt(coords_in.ptr->dt);
935			float cur_depth = distance(pos, ray_o);
936			float density = network_to_density(float(local_network_output[3]), density_activation);
937	
938	
939			const float alpha = 1.f - __expf(-density * dt);
940			const float weight = alpha * T;
941			rgb_ray += weight * rgb;
942			hitpoint += weight * pos;
943			depth_ray += weight * cur_depth;
944			T *= (1.f - alpha);
945	
946			network_output += padded_output_width;
947			coords_in += 1;
948		}
949		hitpoint /= (1.0f - T);
950	
951		// Must be same seed as above to obtain the same
952		// background color.
953		uint32_t ray_idx = ray_indices_in[i];
954		rng.advance(ray_idx * N_MAX_RANDOM_SAMPLES_PER_RAY());
955	
956		float img_pdf = 1.0f;
957		uint32_t img = image_idx(ray_idx, n_rays, n_rays_total, n_training_images, cdf_img, &img_pdf);
958		ivec2 resolution = metadata[img].resolution;
959	
960		float uv_pdf = 1.0f;
961		vec2 uv = nerf_random_image_pos_training(rng, resolution, snap_to_pixel_centers, cdf_x_cond_y, cdf_y, error_map_cdf_res, img, &uv_pdf);
962		float max_level = max_level_rand_training ? (random_val(rng) * 2.0f) : 1.0f; // Multiply by 2 to ensure 50% of training is at max level
963		rng.advance(1);                                                              // motionblur_time
964	
965		if (train_with_random_bg_color) {
966			background_color = random_val_3d(rng);
967		}
968		vec3 pre_envmap_background_color = background_color = srgb_to_linear(background_color);
969	
970		// Composit background behind envmap
971		vec4 envmap_value;
972		vec3 dir;
973		if (envmap) {
974			dir = normalize(rays_in_unnormalized[i].d);
975			envmap_value = read_envmap(envmap, dir);
976			background_color = envmap_value.rgb() + background_color * (1.0f - envmap_value.a);
977		}
978	
979		vec3 exposure_scale = exp(0.6931471805599453f * exposure[img]);
980		// vec3 rgbtarget = composit_and_lerp(uv, resolution, img, training_images, background_color, exposure_scale);
981		// vec3 rgbtarget = composit(uv, resolution, img, training_images, background_color, exposure_scale);
982		vec4 texsamp = read_rgba(uv, resolution, metadata[img].pixels, metadata[img].image_data_type);
983	
984		vec3 rgbtarget;
985		if (train_in_linear_colors || color_space == EColorSpace::Linear) {
986			rgbtarget = exposure_scale * texsamp.rgb() + (1.0f - texsamp.a) * background_color;
987	
988			if (!train_in_linear_colors) {
989				rgbtarget = linear_to_srgb(rgbtarget);
990				background_color = linear_to_srgb(background_color);
991			}
992		} else if (color_space == EColorSpace::SRGB) {
993			background_color = linear_to_srgb(background_color);
994			if (texsamp.a > 0) {
995				rgbtarget = linear_to_srgb(exposure_scale * texsamp.rgb() / texsamp.a) * texsamp.a + (1.0f - texsamp.a) * background_color;
996			} else {
997				rgbtarget = background_color;
998			}
999		}
1000	
1001		if (compacted_numsteps == numsteps) {
1002			// support arbitrary background colors
1003			rgb_ray += T * background_color;
1004		}
1005	
1006		// Step again, this time computing loss
1007		network_output -= padded_output_width * compacted_numsteps; // rewind the pointer
1008		coords_in -= compacted_numsteps;
1009	
1010		uint32_t compacted_base = atomicAdd(numsteps_counter, compacted_numsteps); // first entry in the array is a counter
1011		compacted_numsteps = min(max_samples_compacted - min(max_samples_compacted, compacted_base), compacted_numsteps);
1012		numsteps_in[i * 2 + 0] = compacted_numsteps;
1013		numsteps_in[i * 2 + 1] = compacted_base;
1014		if (compacted_numsteps == 0) {
1015			return;
1016		}
1017	
1018		max_level_compacted_ptr += compacted_base;
1019		coords_out += compacted_base;
1020	
1021		dloss_doutput += compacted_base * padded_output_width;
1022	
1023		LossAndGradient lg = loss_and_gradient(rgbtarget, rgb_ray, loss_type);
1024		lg.loss /= img_pdf * uv_pdf;
1025	
1026		float target_depth = length(rays_in_unnormalized[i].d) *
1027			((depth_supervision_lambda > 0.0f && metadata[img].depth) ? read_depth(uv, resolution, metadata[img].depth) : -1.0f);
1028		LossAndGradient lg_depth = loss_and_gradient(vec3(target_depth), vec3(depth_ray), depth_loss_type);
